export function initialize(sentinel, dotNetHelper) {
    const observer = new IntersectionObserver(async (entries) => {
        if (entries[0].isIntersecting) {
            await dotNetHelper.invokeMethodAsync("OnSentinelVisible");
        }
    }, { rootMargin: "100px" });

    observer.observe(sentinel);

    return { observer, sentinel };
}

export function dispose(instance) {
    if (instance?.observer) {
        instance.observer.unobserve(instance.sentinel);
        instance.observer.disconnect();
    }
}

@typeparam TItem
@implements IAsyncDisposable

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center p-3">
                    <div class="spinner-border text-secondary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

using Microsoft.AspNetCore.Components;
using Microsoft.JSInterop;

namespace sv_20d23cadc0a44d5892b03e07ee12f6b8.Components;

public partial class InfiniteScrollList<TItem> : IAsyncDisposable
{
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Inject]
    private IJSRuntime JS { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observerInstance;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && HasMore)
        {
            await InitializeObserver();
        }
    }

    private async Task InitializeObserver()
    {
        module ??= await JS.InvokeAsync<IJSObjectReference>(
            "import", "./js/infinite-scroll.js");

        dotNetRef = DotNetObjectReference.Create(this);
        observerInstance = await module.InvokeAsync<IJSObjectReference>(
            "initialize", sentinelRef, dotNetRef);
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null && observerInstance is not null)
        {
            try
            {
                await module.InvokeVoidAsync("dispose", observerInstance);
            }
            catch (JSDisconnectedException) { }
        }

        if (observerInstance is not null)
        {
            try { await observerInstance.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }

        if (module is not null)
        {
            try { await module.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }

        dotNetRef?.Dispose();
    }
}

